async function getCalibration() {
    const r = await fetch('/api/calibration').then(res => res.json());
    document.getElementById('calibratedCount').textContent = r.calibrated_count ?? 0;
    return r;
}

async function resetRun() {
    await fetch('/api/reset', { method: 'POST' });
    document.getElementById('log').innerHTML = '<p class="empty">Simulation reset. Waiting for new telemetry...</p>';
    update();
}

async function update() {
    try {
        const [state, cal] = await Promise.all([fetch('/api/state').then(res => res.json()), getCalibration()]);
        if (!state.ready) {
            document.getElementById('grid').innerHTML = '<div class="empty" style="padding: 2rem;">Waiting for devices to warm up...</div>';
            document.getElementById('deviceCount').textContent = state.assets?.length ?? 0;
            document.getElementById('alertCount').textContent = state.alerts?.length ?? 0;
            return;
        }

        document.getElementById('grid').innerHTML = state.assets.map(card).join('');
        document.getElementById('deviceCount').textContent = state.assets.length;
        document.getElementById('alertCount').textContent = state.alerts.length;

        const logEl = document.getElementById('log');
        if (!state.alerts || state.alerts.length === 0) {
            logEl.innerHTML = '<p class="empty">No active anomalies detected.</p>';
        } else {
            logEl.innerHTML = state.alerts.map(a => `
                <div class="log-row">
                    <div class="log-time">${a.time}</div>
                    <div class="log-dev">${a.device}</div>
                    <div class="log-msg">${a.msg}</div>
                    <div class="log-drift">Δ ${a.drift}</div>
                </div>
            `).join('');
        }
    } catch (e) {
        console.error(e);
    }
}

setInterval(update, 1000);
update();

