def tick(self):
    if self.row_source is not None:
        if self.index >= len(self.row_source):
            # Cycle back to beginning for continuous monitoring
            self.index = 0
            if not self.row_source:
                return
        row = self.row_source[self.index]
    else:
        reader = self._ensure_reader()
        row = next(reader, None)
        if row is None:
            # Cycle dataset back to beginning for continuous stream
            self._reader = None
            reader = self._ensure_reader()
            row = next(reader, None)
            if row is None:
                return

    self.index += 1

